import base64
import pickle
import json

def process_pubsub_batch(event, context):
    if 'messages' not in event:
        print("No 'messages' key found in the event. Assuming an empty batch.")
        return

    for message in event['messages']:
        if 'data' in message:
            try:
                # Pub/Sub data is base64 encoded
                encoded_data = message['data']
                decoded_data = base64.b64decode(encoded_data)

                # Deserialize the Python object using pickle
                python_object = pickle.loads(decoded_data)

                # Process the deserialized Python object
                print(f"Successfully deserialized object: {python_object}")
                print(f"Object type: {type(python_object)}")

                # Example: Accessing attributes if it's a known object type
                if hasattr(python_object, 'task_id'):
                    print(f"Processing task_id: {python_object.task_id}")
                if hasattr(python_object, 'payload'):
                    print(f"Payload: {python_object.payload}")

            except base64.binascii.Error as e:
                print(f"Error decoding base64 data for message: {message.get('messageId', 'N/A')}. Error: {e}")
            except pickle.UnpicklingError as e:
                print(f"Error unpickling data for message: {message.get('messageId', 'N/A')}. Error: {e}")
            except Exception as e:
                print(f"An unexpected error occurred for message: {message.get('messageId', 'N/A')}. Error: {e}")
        else:
            print(f"Message {message.get('messageId', 'N/A')} has no 'data' field. Skipping.")

    print("Batch processing complete.")